var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......네, 그렇군요.","JPN":"……ええ、そうなんですね。","ENG":"Yes, I see.","TWN":"……是的，可以這麼說。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다. 스승님께 전달하도록 하죠.","JPN":"わかりました。師匠にお伝えしましょう。","ENG":"Okay, I'll say that to the Master.","TWN":"我知道了。我會轉達給師父的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"갑자기 호출이라니 무슨 일이지? 급한 작전이라도 있나?","JPN":"急に呼び出してどうしたんだ？　緊急作戦か？","ENG":"Why did you call so suddenly? Is there an urgent mission to complete?","TWN":"突然叫我是有什麼事嗎？緊急作戰？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니요. 작전이 아니라 개인적으로 알려드릴 이야기가 있어서 불렀습니다.","JPN":"いいえ、作戦ではなく個人的に話したいことがあってお越しいただきました。","ENG":"No. This is not about a mission. I called you to tell you something personally.","TWN":"不是，不是作戰，是我個人有件事情想告訴您。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"조금 전, 코핀 함의 레이더에 <color=#ffd34c>사냥감</color>의 에너지 시그니처가 감지되었습니다.","JPN":"先ほど、コフィン艦のレーダーに、<color=#ffd34c>獲物</color>のエネルギーシグネチャーが検知されました。","ENG":"A while ago, the Coffin's radar has detected the signature energy of the <color=#ffd34c>Prey</color>.","TWN":"不久前，科芬艦的雷達感知到 <color=#ffd34c>獵物</color>的能量標誌。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"사냥감이라고?","JPN":"獲物だって？","ENG":"The Prey?","TWN":"獵物？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......설마?","JPN":"……まさか？","ENG":"Is that what I think it is?","TWN":"……難不成？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 클리포트 인자 반응입니다. 꽤 오랜만의 일이라 조금 당황스럽긴 하군요.","JPN":"はい、クリフォト・ファクター反応です。かなり久々なので、動揺してしまいますね。","ENG":"Yes, the Qliphoth Factor. I'm surprised too, it's been so long.","TWN":"沒錯。是逆卡巴拉因子反應。好久沒遇到這種情況了，還有些慌張呢。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"설마, 나유빈 그 녀석이 움직였나......","JPN":"まさか、イチノセ・カオル。あいつが動いたのか……","ENG":"Wait, did Na Yubin make a move?","TWN":"難道，是羅瑜斌那傢伙開始行動了嗎……"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다행히도 그건 아닌 것 같습니다.","JPN":"幸いにも、そういうわけではなさそうです。","ENG":"Fortunately, no.","TWN":"所幸並非如此。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"클리포트 인자라고는 해도 미나 양의 그것과는 전혀 다른 타입입니다.","JPN":"クリフォト・ファクターとはいっても、ミナさんとは全く別のタイプですね。","ENG":"This Qliphoth Factor is different from Mina's.","TWN":"雖說是逆卡巴拉因子，但它與劉米娜小姐的逆卡巴拉因子類型完全不同。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 활성화된 클리포트 인자라고 하기에는 강도도 약하고...","JPN":"そもそも活性化されたクリフォト・ファクターにしては強度も足りないですし……","ENG":"Its signal strength is too weak for an activated Qliphoth Factor, too.","TWN":"最初活性化的逆卡巴拉因子強度也很弱……"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쩌면 감지 오류일 수도 있습니다.","JPN":"もしかしたら検知エラーかもしれません。","ENG":"Perhaps this is just a detection error.","TWN":"也有可能是勘測錯誤。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 이쪽 정보는 발견하는 즉시 스승님께 최우선으로 전달해 드리는 게 규칙이라서요.","JPN":"ですが、この手の情報は入手次第、師匠に最優先で伝えることになっていますからね。","ENG":"But as a rule, I must inform you of such information before everyone else.","TWN":"但規定是一旦有這方面的情報，就要立刻向師父報告。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"혹시 괜한 일이었나요?","JPN":"もしかして、余計でしたか？","ENG":"Shouldn't I have told you?","TWN":"我是不是做了多餘的事？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니, 괜찮아.","JPN":"いや、いいんだ。","ENG":"You did the right thing telling me.","TWN":"不，沒有關係。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아직 남아있는 녀석이 있었나 보군.","JPN":"まだ生き残りがいたんだな。","ENG":"Clearly, some of them have survived.","TWN":"看來還有剩下的傢伙啊。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......어떻게 하실 생각입니까?","JPN":"……どうするおつもりで？","ENG":"What are you going to do?","TWN":"……您打算怎麼做？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"역시 예전처럼 <color=#ffd34c>처분</color>하는 건가요?","JPN":"やっぱり、以前のように<color=#ffd34c>処分</color>するのでしょうか？","ENG":"Are you going to <color=#ffd34c>dispose of</color> them like others?","TWN":"果然還是像以前那樣 <color=#ffd34c>處理</color>掉嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니면......","JPN":"もしくは……","ENG":"Or...","TWN":"還是說……"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"활성화되지 않은 클리포트 인자라면 굳이 처분할 필요까진 없어.","JPN":"活性化していないクリフォト・ファクターなら、処分するまでもないだろう。","ENG":"If this Qliphoth Factor is not activated, then no.","TWN":"沒有活性化的逆卡巴拉因子就不是非處理掉不可。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 그게 아니라면...... 그때는 프로토콜대로 처리할 수밖에.","JPN":"だが、そうじゃないなら……その時はプロトコルどおりに処理するしかない。","ENG":"But if it is, then I'll have to follow the protocol.","TWN":"但如果不是的話……到時就只能根據協議處理掉了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐가 됐든 자세히 알려면 현장에 가 봐야겠지.","JPN":"とにかく状況を詳しく知るには、現場に行かないとな。","ENG":"Whichever it is, I'll have to go to the site to know more details.","TWN":"無論如何，要知道更詳細的話就得去現場看看。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님도 꽤나 물러지셨군요.","JPN":"師匠もずいぶん丸くなりましたね。","ENG":"You've become soft, Master.","TWN":"師父也收斂了不少啊。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 누구 때문인지는 짐작이 갑니다만......","JPN":"まあ、誰の影響なのかは見当がつきますが……","ENG":"Well, I think I know who've made you...","TWN":"嗯，雖然大概也能猜測出罪魁禍首是誰……"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연.","JPN":"カナミ。","ENG":"Sooyeon.","TWN":"李秀妍。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"쓸데없는 말이 길어졌군요. 죄송합니다.","JPN":"無駄口をたたいてしまいましたね、すみません。","ENG":"I rambled on. I'm sorry.","TWN":"我廢話太多了呢，非常抱歉。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"발견 위치는 네바다 사막의 비밀 공군기지 근처입니다.","JPN":"発見位置は、ネバダ砂漠にある空軍秘密基地の近くです。","ENG":"It's been discovered near the secret Air Force base in a Nevada desert.","TWN":"發現地點位於內華達沙漠的秘密空軍基地附近。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"클리포트 인자의 영향 탓인지, 해당 지역 인근에 강력한 침식현상이 발생한 상태입니다.","JPN":"クリフォト・ファクターの影響なのか、この地域の近辺に強力な侵食現象が発生しています。","ENG":"Probably because of the Qliphoth Factor, a powerful Counterside effect has occurred around the area.","TWN":"可能是受到逆卡巴拉因子的影響，該區域附近發生了強烈的侵蝕現象。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"최대한 은폐공작을 벌이고 있지만, 위치가 위치인지라 조만간 유력 태스크포스들이 개입할 공산이 큽니다.","JPN":"極力隠ぺいにつとめていますが、場所が場所だけに、じきに有力なタスクフォースが介入する可能性が高いです。","ENG":"We're trying to keep this secret, but given the location, it's only the matter of time before major TASKFORCE companies come flocking.","TWN":"我們正在進行最大程度的隱蔽作業，但該地區已經被定位，遲早會有特遣勢力介入。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"최대한 빠르게 일을 마치시길 권고드립니다.","JPN":"できるだけ早く片づけることをおすすめします。","ENG":"I recommend you take care of it as quickly as possible.","TWN":"建議您儘快完成這項工作。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다녀오시는 동안 회사 일은 출장으로 처리해두겠습니다.","JPN":"不在中、会社では出張扱いにしておきますね。","ENG":"In the meantime, I'll let others know you're on a business trip.","TWN":"您去的期間，公司會當作出差來處理。"},"stage":{"bg":"OFFICE","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 어딘가 재미있는 여행이라도 다녀오실 계획이신가 보죠?","JPN":"ハハ、どこかステキな旅にでも出かけるつもりなんですね？","ENG":"Hah hah. Are you planning to go someplace for fun?","TWN":"哈哈，妳是打算去某個有趣的地方旅行嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"참고로 몰라서 물어보는 건 아닙니다. 스승님.","JPN":"ちなみに、何も知らずに聞いているわけではないですよ、師匠。","ENG":"For your information, I already know where you're going, Master.","TWN":"順便說一聲，我不是因為不知道答案才問妳的喔。師父。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주시윤? 여기서 뭘 하고 있는 거지?","JPN":"シリュウ？　ここで何をしている？","ENG":"Joo Shiyoon? What are you doing here?","TWN":"周時雲？你在這裡做什麼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그야 스승님께서 먼 길을 떠나시는데 그냥 보고만 있을 수는 없죠.","JPN":"そんなの、師匠が遠出されるというのに知らんぷりするわけにはいきませんからね。","ENG":"My Master is about to go on a long journey. I couldn't just sit back.","TWN":"聽到師父要準備要去很遠的地方，那我可不能坐視不管。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제자 된 도리로 짐이라도 들어드릴까 해서요.","JPN":"弟子たるもの、カバン持ちでもさせていただこうかと思いまして。","ENG":"As your apprentice, I thought I could at least help you carry your bag.","TWN":"作為弟子，至少讓我幫妳拿個行李吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"필요없다.","JPN":"必要ない。","ENG":"No, thanks.","TWN":"沒必要。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"애초에 네게 짐을 맡기라니, 고양이에게 생선을 맡기는 게 더 건설적이겠군.","JPN":"そもそも、お前がカバン持ちだなんて、猫にかつおぶしを預けるほうがまだマシだろう。","ENG":"I'd rather trust a cat than you when it comes to my belongings.","TWN":"把行李交給你，我還不如去拜託貓保管小魚乾呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"말이 그렇다는 거죠, 말이.","JPN":"まっ、そういうこともできるって話ですよ。","ENG":"I was just saying.","TWN":"話是這麼說沒錯啦。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"실은 요즘 스승님의 정책이 조금 변한 게 아닐까 하는 걱정이 들던 참이었거든요.","JPN":"実は最近、師匠のポリシーがちょっと変わってきたみたいで、気がかりだったんです。","ENG":"Actually, I've been wondering if your policy has changed.","TWN":"但其實我最近開始擔心師父的行事風格是不是變了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"예를 들어 신입 소대원에 대한 태도라거나 말입니다.","JPN":"たとえば、新人に対する態度とか、ですね。","ENG":"About the treatment of our new squad member, for example.","TWN":"比如說，對待新人的態度或語氣之類的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저도 이 상황을 어떻게 받아들여야 하나 고민하던 참이었는데......","JPN":"僕もこの状況をどう受け止めるべきか悩んでいたところですが……","ENG":"I've been thinking about how to cope with this sudden change, and...","TWN":"我也正苦惱著該如何接受這種情況……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"마침 적절한 시기에 <color=#ffd34c>사냥감</color>이 나타나 주셨네요.","JPN":"ちょうど良いタイミングで<color=#ffd34c>獲物</color>が現れてくれましたね。","ENG":"The <color=#ffd34c>Prey</color> couldn't have chosen more appropriate time to show up.","TWN":"不過剛好這時有 <color=#ffd34c>獵物</color>出現了呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이번에 사냥감을 <color=#ffd34c>처분</color>하는 모습을 보면 저도 스승님이 여전히 예전 그대로라고 생각할 수 있을 것 같아서요.","JPN":"今回こそ獲物の<color=#ffd34c>処分</color>を確認できたら、僕も師匠が昔と変わらないと思えるかもしれません。","ENG":"Maybe if I watch you <color=#ffd34c>dispose of</color> it, I can tell whether or not you've changed.","TWN":"如果能親眼看到師父 <color=#ffd34c>處理</color>掉獵物，我就可以相信師父還是跟以前一樣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 말인데, 이번 사냥에는 저도 동행할까 합니다만...... 괜찮겠죠?","JPN":"というわけで、今回の狩りには僕も同行したいのですが……いいですよね？","ENG":"So I'd like to accompany you on this hunting trip. May I?","TWN":"所以，這次的狩獵我想要和師父一起去……可以吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"말도 안 되는 소릴......","JPN":"何をたわけたことを……","ENG":"Don't be ridiculous.","TWN":"說什麼蠢話……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"물론 거절하신다고 해서 제가 안 따라갈 사람이라고 생각하지는 않으시겠죠?","JPN":"もちろん、断られても僕がそこで断念する人間ではないこと、ご存知ですよね？","ENG":"You know I'll follow you, no matter what you say, right?","TWN":"當然，就算師父拒絕，師父應該也不認為我是那種會乖乖待著不動的人吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이러나 저러나 따라갈 거라면, 적어도 제가 스승님의 시야 안에 있는 게 낫지 않겠습니까?","JPN":"どっちみちついて行くなら、せめて師匠の見える範囲内にいたほうが安心なのでは？","ENG":"And wouldn't it be better, if you can't change my mind, to have me where you can see than where you can't?","TWN":"反正不管怎樣我都會去，那至少待在師父的視線範圍內不是比較好嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"별로 좋은 경험도 아닐 텐데 왜 굳이 따라가려는 건지 모르겠군.","JPN":"あまり良い経験にもならないと思うが、そこまでして同行する意味がわからんな。","ENG":"It's not going to be a good experience. I don't know why you want to follow me.","TWN":"明明不是什麼良好體驗，真不懂為什麼你非要跟著去不可。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"마음대로 해라.","JPN":"勝手にしろ。","ENG":"Do as you please.","TWN":"隨便你吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};